//		on  "type"
//			shift and goto state 1
//	State 1
//		on  '('
//			shift and goto state 2
//		on  identifier
//			call TypeSpec and goto state 3
//	State 2
//		on  ')'
//			shift and goto state 3
//		on  identifier
//			call TypeSpec and goto state 4
//	State 3
//		Accept
//	State 4
//		on  ';'
//			shift and goto state 2
//		on  ')'
//			shift and goto state 3
//
// TypeDecl is used internally from Parse.
func (p *Parser) TypeDecl() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(TypeDecl), 0)
	// state0:
	accept, errorSet = false, 23
	switch Symbol(p.tok.Ch) {
	case TOK_type:
		r = append(r, p.shift())
		goto state1
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = false, 35
	switch Symbol(p.tok.Ch) {
	case TOK_0028:
		r = append(r, p.shift())
		goto state2
	case identifier:
		r = p.add(r, p.TypeSpec())
		goto state3
	}
	return p.stop(r, accept, errorSet)
state2:
	accept, errorSet = false, 40
	switch Symbol(p.tok.Ch) {
	case TOK_0029:
		r = append(r, p.shift())
		goto state3
	case identifier:
		r = p.add(r, p.TypeSpec())
		goto state4
	}
	return p.stop(r, accept, errorSet)
state3:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
state4:
	accept, errorSet = false, 38
	switch Symbol(p.tok.Ch) {
	case TOK_003b:
		r = append(r, p.shift())
		goto state2
	case TOK_0029:
		r = append(r, p.shift())
		goto state3
	}
	return p.stop(r, accept, errorSet)
}

// TypeSpec grammar:
//
//	TypeSpec = identifier [ "=" ] Type .
//
//	State 0
//		on  identifier
//			shift and goto state 1
//	State 1
//		on  '='
//			shift and goto state 2
//		on  "chan", "func", "interface", "struct", '*', '[', identifier
//			call Type and goto state 3
//	State 2
//		on  "chan", "func", "interface", "struct", '*', '[', identifier
//			call Type and goto state 3
//	State 3
//		Accept
//
// TypeSpec is used internally from Parse.
func (p *Parser) TypeSpec() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(TypeSpec), 0)
	// state0:
	accept, errorSet = false, 80
	switch Symbol(p.tok.Ch) {
	case identifier:
		r = append(r, p.shift())
		goto state1
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = false, 8
	switch Symbol(p.tok.Ch) {
	case TOK_003d:
		r = append(r, p.shift())
		goto state2
	case TOK_chan, TOK_func, TOK_interface, TOK_struct, TOK_002a, TOK_005b, identifier:
		r = p.add(r, p.Type())
		goto state3
	}
	return p.stop(r, accept, errorSet)
state2:
	accept, errorSet = false, 9
	switch Symbol(p.tok.Ch) {
	case TOK_chan, TOK_func, TOK_interface, TOK_struct, TOK_002a, TOK_005b, identifier:
		r = p.add(r, p.Type())
		goto state3
	}
	return p.stop(r, accept, errorSet)
state3:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
}

// UnaryExpr grammar:
//
//	UnaryExpr  = { UnaryOp } Factor .
//
//	State 0
//		on  "func", '(', float_lit, identifier, int_lit, rune_lit, string_lit
//			call Factor and goto state 1
//		on  "<-", '!', '&', '*', '+', '-', '^', '~'
//			call UnaryOp and goto state 2
//	State 1
//		Accept
//	State 2
//		on  "func", '(', float_lit, identifier, int_lit, rune_lit, string_lit
//			call Factor and goto state 1
//		on  "<-", '!', '&', '*', '+', '-', '^', '~'
//			call UnaryOp and goto state 2
//
// UnaryExpr is used internally from Parse.
func (p *Parser) UnaryExpr() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(UnaryExpr), 0)
	// state0:
	accept, errorSet = false, 64
	switch Symbol(p.tok.Ch) {
	case TOK_func, TOK_0028, float_lit, identifier, int_lit, rune_lit, string_lit:
		r = p.add(r, p.Factor())
		goto state1
	case TOK_003c002d, TOK_0021, TOK_0026, TOK_002a, TOK_002b, TOK_002d, TOK_005e, TOK_007e:
		r = p.add(r, p.UnaryOp())
		goto state2
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
state2:
	accept, errorSet = false, 64
	switch Symbol(p.tok.Ch) {
	case TOK_func, TOK_0028, float_lit, identifier, int_lit, rune_lit, string_lit:
		r = p.add(r, p.Factor())
		goto state1
	case TOK_003c002d, TOK_0021, TOK_0026, TOK_002a, TOK_002b, TOK_002d, TOK_005e, TOK_007e:
		r = p.add(r, p.UnaryOp())
		goto state2
	}
	return p.stop(r, accept, errorSet)
}

// UnaryOp grammar:
//
//	UnaryOp    = "+" | "-" | "!" | "^" | "*" | "&" | "<-" | "~" .
//
//	State 0
//		on  "<-", '!', '&', '*', '+', '-', '^', '~'
//			shift and goto state 1
//	State 1
//		Accept
//
// UnaryOp is used internally from Parse.
func (p *Parser) UnaryOp() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(UnaryOp), 0)
	// state0:
	accept, errorSet = false, 65
	switch Symbol(p.tok.Ch) {
	case TOK_003c002d, TOK_0021, TOK_0026, TOK_002a, TOK_002b, TOK_002d, TOK_005e, TOK_007e:
		r = append(r, p.shift())
		goto state1
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
}

// VarDecl grammar:
//
//	VarDecl = "var" ( VarSpec | "(" { VarSpec ";" } [ VarSpec ] ")" ) .
//
//	State 0
//		on  "var"
//			shift and goto state 1
//	State 1
//		on  '('
//			shift and goto state 2
//		on  identifier
//			call VarSpec and goto state 3
//	State 2
//		on  ')'
//			shift and goto state 3
//		on  identifier
//			call VarSpec and goto state 4
//	State 3
//		Accept
//	State 4
//		on  ';'
//			shift and goto state 2
//		on  ')'
//			shift and goto state 3
//
// VarDecl is used internally from Parse.
func (p *Parser) VarDecl() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(VarDecl), 0)
	// state0:
	accept, errorSet = false, 24
	switch Symbol(p.tok.Ch) {
	case TOK_var:
		r = append(r, p.shift())
		goto state1
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = false, 34
	switch Symbol(p.tok.Ch) {
	case TOK_0028:
		r = append(r, p.shift())
		goto state2
	case identifier:
		r = p.add(r, p.VarSpec())
		goto state3
	}
	return p.stop(r, accept, errorSet)
state2:
	accept, errorSet = false, 39
	switch Symbol(p.tok.Ch) {
	case TOK_0029:
		r = append(r, p.shift())
		goto state3
	case identifier:
		r = p.add(r, p.VarSpec())
		goto state4
	}
	return p.stop(r, accept, errorSet)
state3:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
state4:
	accept, errorSet = false, 38
	switch Symbol(p.tok.Ch) {
	case TOK_003b:
		r = append(r, p.shift())
		goto state2
	case TOK_0029:
		r = append(r, p.shift())
		goto state3
	}
	return p.stop(r, accept, errorSet)
}

// VarSpec grammar:
//
//	VarSpec = IdentifierList ( Type [ "=" Expression ] | "=" Expression ) .
//
//	State 0
//		on  identifier
//			call IdentifierList and goto state 1
//	State 1
//		on  '='
//			shift and goto state 2
//		on  "chan", "func", "interface", "struct", '*', '[', identifier
//			call Type and goto state 4
//	State 2
//		on  "<-", "func", '!', '&', '(', '*', '+', '-', '^', '~', float_lit, identifier, int_lit, rune_lit, string_lit
//			call Expression and goto state 3
//	State 3
//		Accept
//	State 4
//		Accept
//		on  '='
//			shift and goto state 2
//
// VarSpec is used internally from Parse.
func (p *Parser) VarSpec() (r []int32) {
	accept, errorSet := false, 0
	r = append(p.get(), -int32(VarSpec), 0)
	// state0:
	accept, errorSet = false, 80
	switch Symbol(p.tok.Ch) {
	case identifier:
		r = p.add(r, p.IdentifierList())
		goto state1
	}
	return p.stop(r, accept, errorSet)
state1:
	accept, errorSet = false, 8
	switch Symbol(p.tok.Ch) {
	case TOK_003d:
		r = append(r, p.shift())
		goto state2
	case TOK_chan, TOK_func, TOK_interface, TOK_struct, TOK_002a, TOK_005b, identifier:
		r = p.add(r, p.Type())
		goto state4
	}
	return p.stop(r, accept, errorSet)
state2:
	accept, errorSet = false, 60
	switch Symbol(p.tok.Ch) {
	case TOK_003c002d, TOK_func, TOK_0021, TOK_0026, TOK_0028, TOK_002a, TOK_002b, TOK_002d, TOK_005e, TOK_007e, float_lit, identifier, int_lit, rune_lit, string_lit:
		r = p.add(r, p.Expression())
		goto state3
	}
	return p.stop(r, accept, errorSet)
state3:
	accept, errorSet = true, 0
	return p.stop(r, accept, errorSet)
state4:
	accept, errorSet = true, 72
	switch Symbol(p.tok.Ch) {
	case TOK_003d:
		r = append(r, p.shift())
		goto state2
	}
	return p.stop(r, accept, errorSet)
}

func (p *Parser) shift() (r int32) {
	r = p.tokIndex
	if !p.eof {
		p.tok = p.Scan()
		p.tokIndex++
		p.eof = p.tok.Ch == rune(TOK_EOF)
	}
	return r
}

func (p *Parser) get() (r []int32) {
	if n := len(p.cache); n != 0 {
		r = p.cache[n-1][:0]
		p.cache = p.cache[:n-1]
	}
	return r
}

func (p *Parser) add(r, s []int32) (t []int32) {
	p.cache = append(p.cache, s)
	return append(r, s...)
}

func (p *Parser) stop(r []int32, accept bool, errorSet int) []int32 {
	r[1] = int32(len(r) - 2)
	if !accept {
		p.err(p.tok.Position(), "%q [%s]: expected %v", p.tok.Src(), Symbol(p.tok.Ch), errorSets[errorSet])
	}
	return r
}

// EOF reports whether the parser lookahead token is EOF.
func (p *Parser) EOF() bool {
	return p.eof
}

// Token returns the n-th token in 'p'. Token panics if 'n' is out of range.
func (p *Parser) Token(n int32) (r Token) {
	return p.sc.Token(int(n))
}

// Parse parses 'src'. 'src' becomes "owned" by the parser and must not be
// mutated afterwards.
func (p *Parser) Parse(name string, src []byte) (ast []int32, err error) {
	if err = p.init(name, src); err != nil {
		return nil, err
	}

	defer func() {
		switch e := recover(); x := e.(type) {
		case nil:
			// ok
		case ErrList:
			err = x
		case error:
			err = errors.Join(err, x)
		default:
			err = errors.Join(err, fmt.Errorf("%v", x))
		}
	}()

	p.tok = p.Scan()
	ast = p.SourceFile()
	return ast, p.sc.Err()
}

func (p *Parser) err0(pos token.Position, s string, args ...any) {
	p.sc.AddErr(pos, s, args...)
	if p.errBudget--; p.errBudget == 0 {
		p.sc.AddErr(pos, "too many errors")
	}
}

func (p *Parser) err(pos token.Position, s string, args ...any) {
	p.err0(pos, s, args...)
	p.shift()
	if p.eof {
		panic(p.sc.Err())
	}
}
